update batch.alert_event
set escalation_tier = escalation_tier + 1,
    escalated_at = current_timestamp,
    updated_at = current_timestamp
where id = #{id}
  and tenant_id = #{tenantId}
  and status = 'OPEN'
  and escalation_tier = #{expectedTier}
